// 雙向連結串列節點
class Node<K, V> {
  key: K;
  value: V;
  expiresAt: number | null;
  prev: Node<K, V> | null;
  next: Node<K, V> | null;

  constructor(key: K, value: V, ttlMs?: number) {
    this.key = key;
    this.value = value;
    this.expiresAt = ttlMs ? Date.now() + ttlMs : null;
    this.prev = null;
    this.next = null;
  }

  isExpired(): boolean {
    if (this.expiresAt === null) return false;
    return Date.now() > this.expiresAt;
  }
}

// LRU Cache 實作（帶 TTL 支援）
export class LRUCache<K, V> {
  private capacity: number;
  private defaultTtlMs: number;
  private map: Map<K, Node<K, V>>;
  private head: Node<K, V>; // 虛擬頭節點（most recently used）
  private tail: Node<K, V>; // 虛擬尾節點（least recently used）

  constructor(capacity: number, defaultTtlMs: number = 5000) {
    if (capacity < 1) {
      throw new Error('Capacity must be at least 1');
    }
    this.capacity = capacity;
    this.defaultTtlMs = defaultTtlMs;
    this.map = new Map();

    // 初始化虛擬節點
    this.head = new Node<K, V>(null as unknown as K, null as unknown as V);
    this.tail = new Node<K, V>(null as unknown as K, null as unknown as V);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  // 將節點移到頭部（標記為最近使用）
  private moveToHead(node: Node<K, V>): void {
    this.removeNode(node);
    this.addNodeToHead(node);
  }

  // 從連結串列中移除節點
  private removeNode(node: Node<K, V>): void {
    const prev = node.prev;
    const next = node.next;
    if (prev) prev.next = next;
    if (next) next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  // 將節點新增到頭部
  private addNodeToHead(node: Node<K, V>): void {
    node.next = this.head.next;
    node.prev = this.head;
    if (this.head.next) this.head.next.prev = node;
    this.head.next = node;
  }

  // 移除尾部節點（least recently used）
  private removeTail(): Node<K, V> | null {
    const tailNode = this.tail.prev;
    if (tailNode === this.head || tailNode === null) return null;
    this.removeNode(tailNode);
    return tailNode;
  }

  // 清理已過期的節點
  private cleanupExpired(): void {
    for (const [key, node] of this.map.entries()) {
      if (node.isExpired()) {
        this.map.delete(key);
        this.removeNode(node);
      }
    }
  }

  // 獲取值（會更新使用順序並檢查過期）
  get(key: K): V | undefined {
    this.cleanupExpired();

    const node = this.map.get(key);
    if (!node) return undefined;

    if (node.isExpired()) {
      this.map.delete(key);
      this.removeNode(node);
      return undefined;
    }

    this.moveToHead(node);
    return node.value;
  }

  // 設定值（會更新或新增節點，並檢查容量）
  set(key: K, value: V, ttlMs?: number): void {
    this.cleanupExpired();

    // 檢查 key 是否已存在
    const existingNode = this.map.get(key);
    if (existingNode) {
      existingNode.value = value;
      existingNode.expiresAt = ttlMs !== undefined ? Date.now() + ttlMs : this.defaultTtlMs ? Date.now() + this.defaultTtlMs : null;
      this.moveToHead(existingNode);
      return;
    }

    // 新增節點
    const newNode = new Node<K, V>(key, value, ttlMs !== undefined ? ttlMs : (this.defaultTtlMs > 0 ? this.defaultTtlMs : undefined));
    this.map.set(key, newNode);
    this.addNodeToHead(newNode);

    // 檢查容量，超出則移除最久未使用的節點
    if (this.map.size > this.capacity) {
      const tailNode = this.removeTail();
      if (tailNode) {
        this.map.delete(tailNode.key);
      }
    }
  }

  // 刪除指定 key
  delete(key: K): boolean {
    this.cleanupExpired();

    const node = this.map.get(key);
    if (!node || node.isExpired()) {
      if (node) {
        this.map.delete(key);
        this.removeNode(node);
      }
      return false;
    }

    this.map.delete(key);
    this.removeNode(node);
    return true;
  }

  // 獲取目前大小（排除已過期的）
  get size(): number {
    this.cleanupExpired();
    return this.map.size;
  }

  // 清空所有節點
  clear(): void {
    this.map.clear();
    // 重置連結串列
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }
}

import { strict as assert } from 'assert';
import { LRUCache } from './dist/lru-cache.js';

// 測試基礎 CRUD 操作
function testBasicCRUD() {
  console.log('Testing basic CRUD operations...');
  const cache = new LRUCache<string, string>(3, 5000);

  // set
  cache.set('a', '1');
  cache.set('b', '2');
  cache.set('c', '3');

  // get
  assert.strictEqual(cache.get('a'), '1');
  assert.strictEqual(cache.get('b'), '2');
  assert.strictEqual(cache.get('c'), '3');

  // size
  assert.strictEqual(cache.size, 3);

  // update existing key
  cache.set('a', '100');
  assert.strictEqual(cache.get('a'), '100');

  // delete
  assert.strictEqual(cache.delete('b'), true);
  assert.strictEqual(cache.get('b'), undefined);
  assert.strictEqual(cache.size, 2);

  // delete non-existent
  assert.strictEqual(cache.delete('nonexistent'), false);

  console.log('✓ Basic CRUD tests passed');
}

// 測試 LRU 淘汰策略
function testLRUEviction() {
  console.log('Testing LRU eviction...');
  const cache = new LRUCache<string, string>(3, 5000);

  cache.set('a', '1');
  cache.set('b', '2');
  cache.set('c', '3');

  // 訪問 'a'，使其變成最近使用
  cache.get('a');

  // 新增 'd'，應該淘汰 'b'（least recently used）
  cache.set('d', '4');

  assert.strictEqual(cache.get('b'), undefined);
  assert.strictEqual(cache.get('a'), '1');
  assert.strictEqual(cache.get('c'), '3');
  assert.strictEqual(cache.get('d'), '4');

  console.log('✓ LRU eviction tests passed');
}

// 測試 TTL 過期機制
function testTTLExpiration() {
  console.log('Testing TTL expiration...');
  const cache = new LRUCache<string, string>(3, 100);

  cache.set('a', '1');
  cache.set('b', '2', 50); // b 會在 50ms 後過期

  // 等待過期
  const p1 = new Promise<void>(resolve => setTimeout(() => resolve(), 60));
  const p2 = new Promise<void>(resolve => setTimeout(() => resolve(), 110));

  return Promise.all([p1, p2]).then(() => {
    assert.strictEqual(cache.get('a'), undefined, 'a should be expired');
    assert.strictEqual(cache.get('b'), undefined, 'b should be expired');
    assert.strictEqual(cache.size, 0, 'size should be 0');

    console.log('✓ TTL expiration tests passed');
  });
}

// 測試邊界條件
function testEdgeCases() {
  console.log('Testing edge cases...');

  // capacity = 1
  const singleCache = new LRUCache<string, string>(1, 5000);
  singleCache.set('a', '1');
  assert.strictEqual(singleCache.size, 1);
  singleCache.set('b', '2');
  assert.strictEqual(singleCache.size, 1);
  assert.strictEqual(singleCache.get('a'), undefined);
  assert.strictEqual(singleCache.get('b'), '2');

  // get/set non-existent key
  const cache = new LRUCache<string, string>(3, 5000);
  assert.strictEqual(cache.get('nonexistent'), undefined);
  cache.set('key', 'value');
  cache.set('key', 'newvalue'); // 重複 set
  assert.strictEqual(cache.get('key'), 'newvalue');

  // clear
  cache.clear();
  assert.strictEqual(cache.size, 0);
  assert.strictEqual(cache.get('key'), undefined);

  console.log('✓ Edge case tests passed');
}

// 測試多次 get 不會改變順序（只有 set 才會移動到頭部）
function testGetDoesNotMoveToHead() {
  console.log('Testing that get does not move to head...');

  // 修改：根據 LRU 規範，get 應該移動到頭部
  const cache = new LRUCache<string, string>(3, 5000);
  cache.set('a', '1');
  cache.set('b', '2');
  cache.set('c', '3');

  // get 'a' 應該將 'a' 移到頭部
  cache.get('a');

  // 新增 'd'，應該淘汰 'b' 而不是 'a'
  cache.set('d', '4');

  assert.strictEqual(cache.get('b'), undefined);
  assert.strictEqual(cache.get('a'), '1');

  console.log('✓ Get moves to head tests passed');
}

// 主測試函數
async function runTests() {
  try {
    testBasicCRUD();
    testLRUEviction();
    await testTTLExpiration();
    testEdgeCases();
    testGetDoesNotMoveToHead();

    console.log('\n✅ All tests passed!');
  } catch (error) {
    console.error('\n❌ Test failed:', error);
    process.exit(1);
  }
}

runTests();
